# ===========================================================================
# POST /api/v1/auth/refresh
# ===========================================================================

path '/api/v1/auth/refresh' do
  post 'Refresh access token' do
    tags 'Authentication'
    consumes 'application/json'
    produces 'application/json'

    parameter name: :body, in: :body, schema: {
      type: :object,
      properties: {
        refresh_token: { type: :string, example: 'abc123...' }
      },
      required: %w[refresh_token]
    }

    response '200', 'Token refreshed' do
      schema type: :object,
             properties: {
               access_token: { type: :string },
               user: { '$ref' => '#/components/schemas/user' }
             }

      let!(:credential) { create(:auth_credential) }
      let!(:refresh_token) { create(:refresh_token, :fresh, auth_credential: credential) }
      let(:body) { { refresh_token: refresh_token.token } }
      run_test!
    end

    response '401', 'Invalid or expired refresh token' do
      schema '$ref' => '#/components/schemas/error'

      let(:body) { { refresh_token: 'invalid-token' } }
      run_test!
    end
  end
end

# ===========================================================================
# POST /api/v1/auth/validate
# ===========================================================================

path '/api/v1/auth/validate' do
  post 'Validate access token' do
    tags 'Authentication'
    description 'Used by other microservices to verify tokens'
    produces 'application/json'
    security [bearer_auth: []]

    parameter name: :Authorization, in: :header, type: :string, required: true,
              description: 'Bearer token', example: 'Bearer eyJ...'

    response '200', 'Token is valid' do
      schema type: :object,
             properties: {
               valid: { type: :boolean },
               payload: {
                 type: :object,
                 properties: {
                   sub: { type: :string },
                   email: { type: :string },
                   role: { type: :string },
                   exp: { type: :integer },
                   iat: { type: :integer }
                 }
               }
             }

      let!(:credential) { create(:auth_credential) }
      let(:Authorization) { "Bearer #{JWTService.generate_access_token(credential)}" }
      run_test!
    end

    response '401', 'Token invalid or expired' do
      schema type: :object,
             properties: {
               valid: { type: :boolean },
               error: { type: :string }
             }

      let(:Authorization) { 'Bearer invalid-token' }
      run_test!
    end
  end
end

# ===========================================================================
# GET /api/v1/auth/me
# ===========================================================================

path '/api/v1/auth/me' do
  get 'Get current user info' do
    tags 'Authentication'
    produces 'application/json'
    security [bearer_auth: []]

    parameter name: :Authorization, in: :header, type: :string, required: true,
              description: 'Bearer token', example: 'Bearer eyJ...'

    response '200', 'Current user info' do
      schema type: :object,
             properties: {
               user: { '$ref' => '#/components/schemas/user' }
             }

      let!(:credential) { create(:auth_credential) }
      let(:Authorization) { "Bearer #{JWTService.generate_access_token(credential)}" }
      run_test!
    end

    response '401', 'Unauthorized' do
      schema '$ref' => '#/components/schemas/error'

      let(:Authorization) { '' }
      run_test!
    end
  end
end

# ===========================================================================
# PATCH /api/v1/auth/password
# ===========================================================================

path '/api/v1/auth/password' do
  patch 'Change password' do
    tags 'Authentication'
    consumes 'application/json'
    produces 'application/json'
    security [bearer_auth: []]

    parameter name: :Authorization, in: :header, type: :string, required: true,
              description: 'Bearer token', example: 'Bearer eyJ...'
    parameter name: :body, in: :body, schema: {
      type: :object,
      properties: {
        current_password: { type: :string, example: 'oldpassword14chars' },
        new_password: { type: :string, minLength: 14, example: 'newpassword14chars' },
        new_password_confirmation: { type: :string, example: 'newpassword14chars' }
      },
      required: %w[current_password new_password new_password_confirmation]
    }

    response '200', 'Password updated successfully' do
      schema type: :object,
             properties: {
               message: { type: :string }
             }

      let!(:credential) { create(:auth_credential, password: 'currentpassword14ch') }
      let(:Authorization) { "Bearer #{JWTService.generate_access_token(credential)}" }
      let(:body) do
        {
          current_password: 'currentpassword14ch',
          new_password: 'newpassword14chars',
          new_password_confirmation: 'newpassword14chars'
        }
      end
      run_test!
    end

    response '401', 'Current password incorrect' do
      schema '$ref' => '#/components/schemas/error'

      let!(:credential) { create(:auth_credential, password: 'currentpassword14ch') }
      let(:Authorization) { "Bearer #{JWTService.generate_access_token(credential)}" }
      let(:body) do
        {
          current_password: 'wrongpassword',
          new_password: 'newpassword14chars',
          new_password_confirmation: 'newpassword14chars'
        }
      end
      run_test!
    end

    response '422', 'Validation errors' do
      schema '$ref' => '#/components/schemas/validation_errors'

      let!(:credential) { create(:auth_credential, password: 'currentpassword14ch') }
      let(:Authorization) { "Bearer #{JWTService.generate_access_token(credential)}" }
      let(:body) do
        {
          current_password: 'currentpassword14ch',
          new_password: 'short',
          new_password_confirmation: 'short'
        }
      end
      run_test!
    end
  end
end

# ===========================================================================
# POST /api/v1/auth/forgot-password
# ===========================================================================

path '/api/v1/auth/forgot-password' do
  post 'Request password reset' do
    tags 'Authentication'
    consumes 'application/json'
    produces 'application/json'
    description 'Request a password reset email. Always returns 200 to prevent email enumeration.'

    parameter name: :body, in: :body, schema: {
      type: :object,
      properties: {
        email: { type: :string, format: :email, example: 'user@example.com' }
      },
      required: %w[email]
    }

    response '200', 'Request processed (always returns 200)' do
      schema type: :object,
             properties: {
               message: { type: :string }
             }

      let!(:credential) { create(:auth_credential) }
      let(:body) { { email: credential.email } }
      run_test!
    end
  end
end

# ===========================================================================
# POST /api/v1/auth/reset-password
# ===========================================================================

path '/api/v1/auth/reset-password' do
  post 'Reset password with token' do
    tags 'Authentication'
    consumes 'application/json'
    produces 'application/json'
    description 'Reset password using a token received via email.'

    parameter name: :body, in: :body, schema: {
      type: :object,
      properties: {
        token: { type: :string, example: 'abc123...' },
        new_password: { type: :string, minLength: 14, example: 'mynewsecurepassword' },
        new_password_confirmation: { type: :string, example: 'mynewsecurepassword' }
      },
      required: %w[token new_password new_password_confirmation]
    }

    response '200', 'Password reset successfully' do
      schema type: :object,
             properties: {
               message: { type: :string }
             }

      let!(:credential) { create(:auth_credential) }
      let!(:reset_token) { create(:password_reset_token, auth_credential: credential) }
      let(:body) do
        {
          token: reset_token.token,
          new_password: 'mynewsecurepassword',
          new_password_confirmation: 'mynewsecurepassword'
        }
      end
      run_test!
    end

    response '401', 'Invalid or expired token' do

        schema '$ref' => '#/components/schemas/error'

        let(:body) do
          {
            token: 'invalid-token',
            new_password: 'mynewsecurepassword',
            new_password_confirmation: 'mynewsecurepassword'
          }
        end
        run_test!
      end

      response '422', 'Validation errors' do
        schema '$ref' => '#/components/schemas/validation_errors'

        let!(:credential) { create(:auth_credential) }
        let!(:reset_token) { create(:password_reset_token, auth_credential: credential) }
        let(:body) do
          {
            token: reset_token.token,
            new_password: 'short',
            new_password_confirmation: 'short'
          }
        end
        run_test!
      end
    end
  end

  # ===========================================================================
  # POST /api/v1/auth/verify-email
  # ===========================================================================

  path '/api/v1/auth/verify-email' do
    post 'Verify email address' do
      tags 'Authentication'
      consumes 'application/json'
      produces 'application/json'

