  # POST /api/v1/auth/register
  # ===========================================================================

  path '/api/v1/auth/register' do
    post 'Register a new user' do
      tags 'Authentication'
      consumes 'application/json'
      produces 'application/json'

      parameter name: :body, in: :body, schema: {
        type: :object,
        properties: {
          email: { type: :string, format: :email, example: 'user@example.com' },
          password: { type: :string, minLength: 14, example: 'securepassword14chars' }
        },
        required: %w[email password]
      }

      response '201', 'Account created successfully' do
        schema type: :object,
               properties: {
                 message: { type: :string },
                 user: { '$ref' => '#/components/schemas/user' },
                 access_token: { type: :string },
                 refresh_token: { type: :string }
               }

        let(:body) { { email: 'newuser@example.com', password: 'securepassword14chars' } }
        run_test!
      end

      response '422', 'Validation errors' do
        schema '$ref' => '#/components/schemas/error'

        let(:body) { { email: 'invalid', password: 'short' } }
        run_test!
      end
    end
  end

  # ===========================================================================
  # POST /api/v1/auth/login
  # ===========================================================================

  path '/api/v1/auth/login' do
    post 'Authenticate user' do
      tags 'Authentication'
      consumes 'application/json'
      produces 'application/json'

      parameter name: :body, in: :body, schema: {
        type: :object,
        properties: {
          email: { type: :string, format: :email, example: 'user@example.com' },
          password: { type: :string, example: 'securepassword14chars' }
        },
        required: %w[email password]
      }

      response '200', 'Login successful' do
        schema type: :object,
               properties: {
                 message: { type: :string },
                 user: { '$ref' => '#/components/schemas/user' },
                 access_token: { type: :string },
                 refresh_token: { type: :string }
               }

        let!(:credential) { create(:auth_credential, email: 'test@example.com', password: 'correctpassword14') }
        let(:body) { { email: 'test@example.com', password: 'correctpassword14' } }
        run_test!
      end

      response '401', 'Invalid credentials' do
        schema '$ref' => '#/components/schemas/error'

        let(:body) { { email: 'wrong@example.com', password: 'wrongpassword' } }
        run_test!
      end
    end
  end

  # ===========================================================================
  # POST /api/v1/auth/logout
  # ===========================================================================

  path '/api/v1/auth/logout' do
    post 'Logout user' do
      tags 'Authentication'
      consumes 'application/json'
      produces 'application/json'
      security [bearer_auth: []]

      parameter name: :Authorization, in: :header, type: :string, required: true,
                description: 'Bearer token', example: 'Bearer eyJ...'
      parameter name: :body, in: :body, schema: {
        type: :object,
        properties: {
          refresh_token: { type: :string, example: 'abc123...' }
        },
        required: %w[refresh_token]
      }

      response '200', 'Logged out successfully' do
        schema type: :object,
               properties: {
                 message: { type: :string }
               }

        let!(:credential) { create(:auth_credential) }
        let!(:refresh_token) { create(:refresh_token, auth_credential: credential) }
        let(:Authorization) { "Bearer #{JWTService.generate_access_token(credential)}" }
        let(:body) { { refresh_token: refresh_token.token } }
        run_test!
      end

      response '401', 'Unauthorized' do
        schema '$ref' => '#/components/schemas/error'

        let(:Authorization) { '' }
        let(:body) { { refresh_token: 'invalid' } }
        run_test!
      end
    end
  end

  # ===========================================================================
  # POST /api/v1/auth/refresh
  # ===========================================================================

