      produces 'application/json'
      security [bearer_auth: []]

      parameter name: :Authorization, in: :header, type: :string, required: true,
                description: 'Bearer token', example: 'Bearer eyJ...'
      parameter name: :body, in: :body, schema: {
        type: :object,
        properties: {
          current_password: { type: :string, example: 'oldpassword14chars' },
          new_password: { type: :string, minLength: 14, example: 'newpassword14chars' },
          new_password_confirmation: { type: :string, example: 'newpassword14chars' }
        },
        required: %w[current_password new_password new_password_confirmation]
      }

      response '200', 'Password updated successfully' do
        schema type: :object,
               properties: {
                 message: { type: :string }
               }

        let!(:credential) { create(:auth_credential, password: 'currentpassword14ch') }
        let(:Authorization) { "Bearer #{JWTService.generate_access_token(credential)}" }
        let(:body) do
          {
            current_password: 'currentpassword14ch',
            new_password: 'newpassword14chars',
            new_password_confirmation: 'newpassword14chars'
          }
        end
        run_test!
      end

      response '401', 'Current password incorrect' do
        schema '$ref' => '#/components/schemas/error'

        let!(:credential) { create(:auth_credential, password: 'currentpassword14ch') }
        let(:Authorization) { "Bearer #{JWTService.generate_access_token(credential)}" }
        let(:body) do
          {
            current_password: 'wrongpassword',
            new_password: 'newpassword14chars',
            new_password_confirmation: 'newpassword14chars'
          }
        end
        run_test!
      end

      response '422', 'Validation error' do
        schema '$ref' => '#/components/schemas/error'

        let!(:credential) { create(:auth_credential, password: 'currentpassword14ch') }
        let(:Authorization) { "Bearer #{JWTService.generate_access_token(credential)}" }
        let(:body) do
          {
            current_password: 'currentpassword14ch',
            new_password: 'short',
            new_password_confirmation: 'short'
          }
        end
        run_test!
      end
    end
  end

