        let!(:credential) { create(:auth_credential, password: 'currentpassword14ch') }
        let(:Authorization) { "Bearer #{JWTService.generate_access_token(credential)}" }
        let(:body) do
          {
            current_password: 'currentpassword14ch',
            new_password: 'short',
            new_password_confirmation: 'short'
          }
        end
        run_test!
      end
    end
  end

  # ===========================================================================
  # POST /api/v1/auth/forgot-password
  # ===========================================================================

  path '/api/v1/auth/forgot-password' do
    post 'Request password reset' do
      tags 'Authentication'
      consumes 'application/json'
      produces 'application/json'
      description 'Request a password reset email. Always returns 200 to prevent email enumeration.'

      parameter name: :body, in: :body, schema: {
        type: :object,
        properties: {
          email: { type: :string, format: :email, example: 'user@example.com' }
        },
        required: %w[email]
      }

      response '200', 'Request processed (always returns 200)' do
        schema type: :object,
               properties: {
                 message: { type: :string }
               }

        let!(:credential) { create(:auth_credential) }
        let(:body) { { email: credential.email } }
        run_test!
      end
    end
  end

  # ===========================================================================
  # POST /api/v1/auth/reset-password
  # ===========================================================================

  path '/api/v1/auth/reset-password' do
    post 'Reset password with token' do
      tags 'Authentication'
      consumes 'application/json'
      produces 'application/json'
      description 'Reset password using a token received via email.'

      parameter name: :body, in: :body, schema: {
        type: :object,
        properties: {
          token: { type: :string, example: 'abc123...' },
          new_password: { type: :string, minLength: 14, example: 'mynewsecurepassword' },
          new_password_confirmation: { type: :string, example: 'mynewsecurepassword' }
        },
        required: %w[token new_password new_password_confirmation]
      }

      response '200', 'Password reset successfully' do
        schema type: :object,
               properties: {
                 message: { type: :string }
               }

        let!(:credential) { create(:auth_credential) }
        let!(:reset_token) { create(:password_reset_token, auth_credential: credential) }
        let(:body) do
          {
            token: reset_token.token,
            new_password: 'mynewsecurepassword',
            new_password_confirmation: 'mynewsecurepassword'
          }
        end
        run_test!
      end

      response '401', 'Invalid or expired token' do
        schema '$ref' => '#/components/schemas/error'

        let(:body) do
          {
            token: 'invalid-token',
            new_password: 'mynewsecurepassword',
            new_password_confirmation: 'mynewsecurepassword'
          }
        end
        run_test!
      end

      response '422', 'Validation error' do
        schema '$ref' => '#/components/schemas/error'

        let!(:credential) { create(:auth_credential) }
        let!(:reset_token) { create(:password_reset_token, auth_credential: credential) }
        let(:body) do
          {
            token: reset_token.token,
            new_password: 'short',
            new_password_confirmation: 'short'
          }
        end
        run_test!
      end
    end
  end

  # ===========================================================================
  # POST /api/v1/auth/verify-email
  # ===========================================================================

  path '/api/v1/auth/verify-email' do
    post 'Verify email address' do
      tags 'Authentication'
      consumes 'application/json'
      produces 'application/json'

      parameter name: :body, in: :body, schema: {
        type: :object,
        properties: {
          token: { type: :string, example: 'abc123...' }
        },
        required: %w[token]
      }

      response '200', 'Email verified successfully' do
        schema type: :object,
               properties: {
                 message: { type: :string }
               }

        let!(:credential) { create(:auth_credential) }
        let!(:verification_token) { create(:email_verification_token, auth_credential: credential) }
        let(:body) { { token: verification_token.token } }
        run_test!
      end

      response '401', 'Invalid or expired token' do
        schema '$ref' => '#/components/schemas/error'

        let(:body) { { token: 'invalid-token' } }
        run_test!
      end
    end
  end
end
