import client from './client'
import type { AdminUser } from '@/types/auth'

export interface UsersResponse {
  users: AdminUser[]
}

export interface UserResponse {
  user: AdminUser
}

export interface ActionResponse {
  message: string
  user: AdminUser
}

export const adminApi = {
  listUsers: () => client.get<UsersResponse>('/api/v1/admin/users'),

  getUser: (id: string) => client.get<UserResponse>(`/api/v1/admin/users/${id}`),

  deactivateUser: (id: string) =>
    client.patch<ActionResponse>(`/api/v1/admin/users/${id}/deactivate`),

  activateUser: (id: string) =>
    client.patch<ActionResponse>(`/api/v1/admin/users/${id}/activate`),
}

